INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3c4f5c38-7669-4008-a2f0-40aecc1e9b8a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Go Testing — The Philosophy Behind `testing.T` and Table-Driven Tests$escape$,
  $escape$Go's standard library ships its own test runner — no Jest, no pytest, no external framework needed. The `testing` package and `go test` command are first-class citizens of the toolchain. Go's testing philosophy is deliberately minimal: no assertions, no matchers, no magic. You call `t.Errorf` or `t.Fatalf` and move on. This forces you to write explicit failure messages, which makes broken tests self-documenting.

The idiomatic pattern is table-driven tests: a slice of anonymous structs, each holding inputs and expected outputs, iterated in a single `for _, tc := range tests` loop. This scales cleanly — adding a new case is one struct literal, not a new function.

Use `t.Run(tc.name, func(t *testing.T) {...})` to turn each table entry into a named subtest. This gives you targeted reruns via `go test -run TestAdd/negative` and parallel subtests via `t.Parallel()`. For HTTP handlers, `net/http/httptest.NewRecorder()` eliminates the need for mocking frameworks entirely.$escape$,
  $escape$func TestAdd(t *testing.T) {
	tests := []struct {
		name string
		a, b int
		want int
	}{
		{"positive", 2, 3, 5},
		{"negative", -1, -2, -3},
		{"zero", 0, 0, 0},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			if got := Add(tc.a, tc.b); got != tc.want {
				t.Errorf("Add(%d, %d) = %d, want %d", tc.a, tc.b, got, tc.want)
			}
		})
	}
}$escape$,
