INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e4058eee-ddca-43ae-aa21-410cb9352883',
  '00000000-0000-0000-0000-000000000001',
  $escape$Go Benchmarking — Using testing.B to Profile Real Bottlenecks$escape$,
  $escape$Go's `testing` package ships with a first-class benchmarking harness — no third-party tools needed. Benchmark functions receive a `*testing.B`, and the runtime automatically calibrates `b.N` so each run is statistically meaningful. Run with `go test -bench=. -benchmem` to get ns/op, allocs/op, and B/op in one pass.

For CPU profiling, add `-cpuprofile=cpu.out` and inspect with `go tool pprof cpu.out`. The `top`, `list <func>`, and `web` commands inside pprof pinpoint hot paths down to the source line. For heap pressure, swap in `-memprofile=mem.out`.

Use `b.ResetTimer()` after any expensive setup so setup cost doesn't pollute results. Use `b.ReportAllocs()` to force allocation reporting even without `-benchmem`. Avoid the compiler optimizing away your result — assign to a package-level sink variable. The Go runtime's escape analysis means stack vs. heap placement changes benchmark numbers significantly; understanding why an alloc escapes is often the real insight.$escape$,
  $escape$package main

import (
	"strings"
	"testing"
)

var sink string

func BenchmarkStringJoin(b *testing.B) {
	parts := []string{"go", "bench", "mark", "test"}
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		sink = strings.Join(parts, "-")
	}
}$escape$,
  $escape$go$escape$,
