INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ebccca58-342c-4f3d-a31f-3c2f0451f4a1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Go Linting — Enforcing Idiomatic Code with golangci-lint$escape$,
  $escape$Go ships with `gofmt` and `go vet`, but production teams need more. `golangci-lint` is the de facto meta-linter that runs dozens of analyzers in a single pass. Key linters to enable: `staticcheck` catches deprecated API usage and unreachable code; `errcheck` enforces that no error return is silently discarded; `gosimple` flags patterns like `select` with a single `case` that should just be a channel receive; `unparam` finds parameters that always receive the same value. The `revive` linter enforces Go idioms — exported types without doc comments, receiver naming consistency, and stuttering identifiers (e.g. `user.UserID` → `user.ID`). Configure via `.golangci.yml` at repo root. Enable `exhaustive` for exhaustive enum `switch` checks on your own types. Use `wrapcheck` to enforce that errors from external packages are always wrapped with `%w` for proper `errors.Is` / `errors.As` unwrapping. Run locally and in CI with `golangci-lint run ./...` to catch issues before review.$escape$,
  $escape$# .golangci.yml
linters:
  enable:
    - staticcheck
    - errcheck
    - gosimple
    - unparam
    - revive
    - exhaustive
    - wrapcheck

linters-settings:
  wrapcheck:
    ignorePackageGlobs:
      - "your/internal/*"
  exhaustive:
    default-signifies-exhaustive: true

run:
  timeout: 5m$escape$,
  $escape$bash$escape$,
