INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c0c19338-e002-4968-8add-e762793865be',
  '00000000-0000-0000-0000-000000000001',
  $escape$Go Deployment — Tiny Binaries, Zero-Dependency Containers$escape$,
  $escape$Go compiles to a single statically-linked binary by default, but default builds still pull in CGo and the standard library's DNS resolver, which bloat size and require glibc. Disable CGo entirely with CGO_ENABLED=0 to get a truly static binary — no shared libraries, no runtime deps. Pair this with ldflags to strip debug info and DWARF tables, shrinking binaries by 20–40%. For containers, build FROM scratch: the image contains only your binary. No shell, no package manager, no attack surface. Multi-stage Dockerfiles make this clean — compile in golang:1.23-alpine, copy the binary to scratch. The resulting image is often under 15MB vs 300MB+ for debian-based Go images. One caveat: scratch images can't use os/user or net package's CGo DNS path — use GODEBUG=netdns=go to force the pure-Go resolver. For CA certificates (HTTPS clients), copy /etc/ssl/certs/ca-certificates.crt from the builder stage. With these three levers — CGO_ENABLED=0, ldflags, and scratch — Go's deployment story is unmatched.$escape$,
  $escape$# Multi-stage build: static binary in a scratch container
FROM golang:1.23-alpine AS builder
WORKDIR /app
COPY . .
RUN CGO_ENABLED=0 GOOS=linux go build \
    -ldflags="-s -w" \
    -o server ./cmd/server

FROM scratch
COPY --from=builder /etc/ssl/certs/ca-certificates.crt /etc/ssl/certs/
COPY --from=builder /app/server /server
ENV GODEBUG=netdns=go
ENTRYPOINT ["/server"]$escape$,
  $escape$bash$escape$,
