INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '27c1f71c-6cda-4215-95ce-569f2dca6a77',
  '00000000-0000-0000-0000-000000000001',
  $escape$Go's Goroutine Model — What It Actually Means for Horizontal Scaling$escape$,
  $escape$Go uses an M:N scheduler: N goroutines multiplexed onto M OS threads, where M is controlled by `runtime.GOMAXPROCS` (defaults to `runtime.NumCPU()`). Each goroutine starts at a 2KB stack that grows dynamically, so spawning thousands per request is cheap — `net/http` does exactly this, one goroutine per inbound connection.

For horizontal scaling, the implication is sharp: Go services are naturally stateless-friendly. Since goroutines don't map 1:1 to threads, I/O-bound handlers (DB calls, upstream HTTP) park the goroutine without blocking an OS thread — the scheduler runs other goroutines on that thread instead. This means a single pod saturates CPU before it runs out of concurrency headroom.

When scaling out, keep per-request state in the request context (`context.Context`), not in package-level variables. Any shared mutable state — counters, caches — must use `sync/atomic` or a `sync.Mutex`, because multiple goroutines will race across multiple CPUs. Horizontal replicas share nothing by default; coordination belongs in Redis or PostgreSQL, not in Go heap memory.$escape$,
  $escape$package main

import (
	"fmt"
	"net/http"
	"runtime"
	"sync/atomic"
)

var reqCount atomic.Int64

func handler(w http.ResponseWriter, r *http.Request) {
	// Safe across goroutines on all GOMAXPROCS threads
	count := reqCount.Add(1)
	fmt.Fprintf(w, "goroutines=%d req=%d", runtime.NumGoroutine(), count)
}

func main() {
	runtime.GOMAXPROCS(runtime.NumCPU()) // default, shown explicitly
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}$escape$,
  $escape$go$escape$,
