INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f91b2c45-0731-48c8-85c4-930ba6385219',
  '00000000-0000-0000-0000-000000000001',
  $escape$Go Runtime Metrics — Profiling GC Pauses and Memory in Production$escape$,
  $escape$Go's `runtime` and `runtime/metrics` packages expose everything you need to monitor your process without external agents. Since Go 1.16, `metrics.Read()` replaces fragile `runtime.ReadMemStats()` calls — it's lower overhead and doesn't stop the world.

For GC pause visibility, sample `/gc/pauses:seconds` and `/gc/cycles/total:gc-cycles`. Pair these with `/memory/classes/heap/objects:bytes` to correlate allocation pressure with pause spikes. In production, wrap this in a goroutine that ticks every 30s and emits to your metrics backend.

For CPU profiling without redeploying, register `net/http/pprof` on a private port — never expose it publicly. Hit `/debug/pprof/profile?seconds=30` during a live incident to capture a 30-second CPU flame graph. For GC-specific traces, use `runtime/trace` with `trace.Start()` and analyze with `go tool trace`.

Set `GODEBUG=gctrace=1` in staging to get per-cycle GC output to stderr: pause duration, heap size before/after, and trigger reason. This is the fastest way to distinguish allocation-heavy code from GC tuning issues. Tune `GOGC` (default 100) to trade CPU for memory — lowering it reduces heap growth but increases GC frequency.$escape$,
  $escape$package main

import (
	"runtime/metrics"
	"time"
	"log"
)

func collectGCMetrics() {
	descs := []metrics.Sample{
		{Name: "/gc/pauses:seconds"},
		{Name: "/memory/classes/heap/objects:bytes"},
		{Name: "/gc/cycles/total:gc-cycles"},
	}
	for range time.Tick(30 * time.Second) {
		metrics.Read(descs)
		log.Printf("heap_objects=%.2fMB gc_cycles=%v",
			float64(descs[1].Value.Uint64())/(1<<20),
			descs[2].Value.Uint64(),
		)
	}
}$escape$,
  $escape$go$escape$,
